proof fn phi_1_implies_apply_closure_bridge(ex: Execution<int>, p: TempPred<int>, q: TempPred<int>)
    requires
        p.satisfied_by(ex),
        (p.pred)(ex) ==> (q.pred)(ex),
    ensures
        q.satisfied_by(ex),
{
    implies_apply::<int>(ex, p, q);
}

proof fn phi_2_entails_trans_unbounded_chain(p: TempPred<int>, q: TempPred<int>, r: TempPred<int>, s: TempPred<int>)
    requires
        p.entails(q),
        q.entails(r),
        r.entails(s),
    ensures
        p.entails(s),
{
    entails_trans::<int>(p, q, r);
    entails_trans::<int>(p, r, s);
}

proof fn phi_3_valid_implies_entails_anything(p: TempPred<int>, spec: TempPred<int>)
    requires
        valid(p),
    ensures
        spec.entails(p),
{
    assert forall |ex| #[trigger] spec.satisfied_by(ex) implies p.satisfied_by(ex) by {
        implies_apply::<int>(ex, spec, p);
    };
}

