proof fn phi_5_entails_reflexive(p: TempPred<int>)
    ensures
        p.entails(p),
{
    assert forall |ex| #[trigger] p.satisfied_by(ex) implies p.satisfied_by(ex) by {
        implies_apply::<int>(ex, p, p);
    };
